import React, { useEffect, useState } from 'react';
import AppLayout from '../components/shared/AppLayout';
import LoadingSpinner from '../components/shared/LoadingSpinner';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import toast from 'react-hot-toast';

export default function CharityPage() {
  const { user, refreshUser } = useAuth();
  const [charities, setCharities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(user?.charity_id?._id || user?.charity_id || '');
  const [percentage, setPercentage] = useState(user?.charity_percentage || 10);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    api.get('/charities')
      .then(r => setCharities(r.data.charities))
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    if (!selected) return toast.error('Please select a charity');
    if (percentage < 10 || percentage > 100) return toast.error('Percentage must be 10–100');
    setSaving(true);
    try {
      await api.post('/charities/select', { charity_id: selected, charity_percentage: percentage });
      await refreshUser();
      toast.success('Charity preference saved! 💚');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save');
    } finally {
      setSaving(false);
    }
  };

  const currentCharityId = user?.charity_id?._id || user?.charity_id;

  return (
    <AppLayout>
      <div className="max-w-4xl mx-auto space-y-8 animate-slide-up">
        <div>
          <h1 className="page-title">My Charity</h1>
          <p className="text-charcoal-400 mt-1">Choose a cause that matters to you — a portion of your subscription goes directly to them.</p>
        </div>

        {/* Current selection banner */}
        {currentCharityId && (
          <div className="card border border-forest-800/40 bg-forest-900/10">
            <div className="flex items-center gap-3">
              <div className="text-2xl">💚</div>
              <div>
                <p className="text-sm text-forest-400 font-medium">Currently supporting</p>
                <p className="text-white font-semibold">{user.charity_id?.name || 'Your selected charity'}</p>
              </div>
              <div className="ml-auto text-right">
                <p className="text-2xl font-display font-bold text-forest-400">{user.charity_percentage}%</p>
                <p className="text-xs text-charcoal-500">of your subscription</p>
              </div>
            </div>
          </div>
        )}

        {/* Contribution slider */}
        <div className="card">
          <h2 className="section-title mb-4">Contribution Percentage</h2>
          <p className="text-charcoal-400 text-sm mb-5">
            Choose what percentage of your subscription fee goes to your charity. Minimum 10%.
          </p>
          <div className="flex items-center gap-4">
            <input
              type="range"
              min="10"
              max="100"
              step="5"
              value={percentage}
              onChange={e => setPercentage(Number(e.target.value))}
              className="flex-1 accent-forest-500"
            />
            <div className="w-20 text-center">
              <span className="font-display text-3xl font-bold text-forest-400">{percentage}</span>
              <span className="text-charcoal-400 text-sm">%</span>
            </div>
          </div>
          <div className="flex justify-between text-xs text-charcoal-600 mt-1 px-1">
            <span>10% min</span>
            <span>100% max</span>
          </div>
        </div>

        {/* Charity grid */}
        {loading ? (
          <div className="flex justify-center py-10"><LoadingSpinner size="lg" /></div>
        ) : (
          <div>
            <h2 className="section-title mb-5">Select a Charity</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {charities.map(charity => {
                const isSelected = selected === charity._id;
                return (
                  <button
                    key={charity._id}
                    onClick={() => setSelected(charity._id)}
                    className={`text-left rounded-2xl border p-5 transition-all duration-200 group ${
                      isSelected
                        ? 'border-forest-600 bg-forest-900/20 shadow-lg shadow-forest-900/20'
                        : 'border-charcoal-800 bg-charcoal-900/40 hover:border-charcoal-700 hover:bg-charcoal-900/60'
                    }`}
                  >
                    <div className="relative mb-4 rounded-xl overflow-hidden h-32 bg-charcoal-800">
                      {charity.image ? (
                        <img
                          src={charity.image}
                          alt={charity.name}
                          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-4xl">💚</div>
                      )}
                      {isSelected && (
                        <div className="absolute inset-0 bg-forest-600/20 flex items-center justify-center">
                          <div className="w-10 h-10 rounded-full bg-forest-600 flex items-center justify-center">
                            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" />
                            </svg>
                          </div>
                        </div>
                      )}
                    </div>
                    <h3 className={`font-display font-semibold mb-1.5 text-sm leading-snug ${isSelected ? 'text-forest-300' : 'text-white'}`}>
                      {charity.name}
                    </h3>
                    <p className="text-xs text-charcoal-500 leading-relaxed line-clamp-2">
                      {charity.description}
                    </p>
                    {isSelected && (
                      <div className="mt-3 text-xs font-semibold text-forest-400 flex items-center gap-1">
                        <span>✓</span> Selected
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* Save button */}
        <div className="flex justify-end">
          <button
            onClick={handleSave}
            disabled={saving || !selected}
            className="btn-primary px-8"
          >
            {saving ? 'Saving...' : 'Save Preference'}
          </button>
        </div>
      </div>
    </AppLayout>
  );
}
